175	/* ────────────────────────────────────────────────────────────────────── */
176	/* Wall Opening — §16 Openings                                            */
177	/* ────────────────────────────────────────────────────────────────────── */
178	
179	export interface WallOpeningState {
180	  phase: 'pick-wall' | 'define-rect';
181	  hostWallId: string | null;
182	  anchorMm: { xMm: number; yMm: number } | null;
183	}
184	
185	export type WallOpeningEvent =
186	  | { kind: 'activate' }
187	  | { kind: 'deactivate' }
188	  | { kind: 'click-wall'; wallId: string; pointMm: { xMm: number; yMm: number } }
189	  | { kind: 'drag-end'; cornerMm: { xMm: number; yMm: number } }
190	  | { kind: 'cancel' };
191	
192	export interface WallOpeningEffect {
193	  commitWallOpening?: {
194	    hostWallId: string;
195	    anchorMm: { xMm: number; yMm: number };
196	    cornerMm: { xMm: number; yMm: number };
197	  };
198	  stillActive: boolean;
199	}
200	
201	export function initialWallOpeningState(): WallOpeningState {
202	  return { phase: 'pick-wall', hostWallId: null, anchorMm: null };
203	}
204	
205	export function reduceWallOpening(
206	  state: WallOpeningState,
207	  event: WallOpeningEvent,
208	): { state: WallOpeningState; effect: WallOpeningEffect } {
209	  if (event.kind === 'activate') {
210	    return { state: initialWallOpeningState(), effect: { stillActive: true } };
211	  }
212	  if (event.kind === 'deactivate') {
213	    return { state: initialWallOpeningState(), effect: { stillActive: false } };
214	  }
215	  if (event.kind === 'cancel') {
216	    return { state: initialWallOpeningState(), effect: { stillActive: true } };
217	  }
218	  if (event.kind === 'click-wall' && state.phase === 'pick-wall') {
219	    return {
220	      state: { phase: 'define-rect', hostWallId: event.wallId, anchorMm: event.pointMm },
221	      effect: { stillActive: true },
222	    };
223	  }
224	  if (event.kind === 'drag-end' && state.phase === 'define-rect' && state.hostWallId && state.anchorMm) {
225	    return {
226	      state: initialWallOpeningState(),
227	      effect: {
228	        commitWallOpening: {
229	          hostWallId: state.hostWallId,
230	          anchorMm: state.anchorMm,
231	          cornerMm: event.cornerMm,
232	        },
233	        stillActive: true,
234	      },
235	    };
236	  }
237	  return { state, effect: { stillActive: true } };
238	}
239	
240	/* ────────────────────────────────────────────────────────────────────── */
241	/* Shaft — §16 Openings                                                   */
242	/* ────────────────────────────────────────────────────────────────────── */
243	
244	export interface ShaftState {
245	  phase: 'idle' | 'sketch';
246	  verticesMm: Array<{ xMm: number; yMm: number }>;
247	}
248	
249	export type ShaftEvent =
250	  | { kind: 'activate' }
251	  | { kind: 'deactivate' }
252	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
253	  | { kind: 'close-loop' }
254	  | { kind: 'cancel' };
255	
256	export interface ShaftEffect {
257	  commitShaft?: { verticesMm: Array<{ xMm: number; yMm: number }> };
258	  stillActive: boolean;
259	}
260	
261	export function initialShaftState(): ShaftState {
262	  return { phase: 'idle', verticesMm: [] };
263	}
264	
265	export function reduceShaft(
266	  state: ShaftState,
267	  event: ShaftEvent,
268	): { state: ShaftState; effect: ShaftEffect } {
269	  if (event.kind === 'activate') {
270	    return { state: initialShaftState(), effect: { stillActive: true } };
271	  }
272	  if (event.kind === 'deactivate') {
273	    return { state: initialShaftState(), effect: { stillActive: false } };
274	  }
275	  if (event.kind === 'cancel') {
276	    return { state: initialShaftState(), effect: { stillActive: true } };
277	  }
278	  if (event.kind === 'click') {
279	    return {
280	      state: { phase: 'sketch', verticesMm: [...state.verticesMm, event.pointMm] },
281	      effect: { stillActive: true },
282	    };
283	  }
284	  if (event.kind === 'close-loop' && state.verticesMm.length >= 3) {
285	    return {
286	      state: initialShaftState(),
287	      effect: { commitShaft: { verticesMm: state.verticesMm }, stillActive: true },
288	    };
289	  }
290	  return { state, effect: { stillActive: true } };
291	}
292	```
