53	const SLICE_Y = 0.02;
54	
55	// B03 — spec 1:5–1:5000 plan scale bounds  half = plotScale * 500mm / 1000
56	const HALF_MIN = 2.5; // 1:5 (very close)
57	const HALF_MAX = 2500; // 1:5000 (very far)
