59	function orthoExtents(halfWorldM: number) {
60	  const stepMm = halfWorldM < 5 ? 250 : halfWorldM < 12 ? 500 : halfWorldM < 24 ? 1000 : 2000;
61	  const snapMm = Math.max(stepMm * 3, 300);
62	  return { stepMm, snapMm };
63	}
64	
65	function rayToPlanMm(
66	  renderer: THREE.WebGLRenderer,
67	  camera: THREE.Camera,
68	  clientX: number,
69	  clientY: number,
70	) {
71	  const rect = renderer.domElement.getBoundingClientRect();
72	  const ndc = new THREE.Vector2(
73	    ((clientX - rect.left) / rect.width) * 2 - 1,
74	    -(((clientY - rect.top) / rect.height) * 2 - 1),
75	  );
76	  const raycaster = new THREE.Raycaster();
77	  raycaster.setFromCamera(ndc, camera);
78	  const plane = new THREE.Plane(new THREE.Vector3(0, 1, 0), -SLICE_Y);
79	  const pt = new THREE.Vector3();
80	  if (!raycaster.ray.intersectPlane(plane, pt)) return null;
81	  return { xMm: pt.x * 1000, yMm: pt.z * 1000 };
82	}
