84	type Draft =
85	  | { kind: 'wall'; sx: number; sy: number }
86	  | { kind: 'room'; verts: Array<{ xMm: number; yMm: number }> }
87	  | { kind: 'grid'; sx: number; sy: number }
88	  | { kind: 'dim'; ax: number; ay: number }
89	  | { kind: 'room_rect'; sx: number; sy: number };
90	
91	function nearestWallAt(
92	  elementsById: Record<string, Element>,
93	  activeLevelId: string | undefined,
94	  xMm: number,
95	  yMm: number,
96	): { wall: Extract<Element, { kind: 'wall' }>; alongT: number; distMm: number } | undefined {
97	  const px = xMm / 1000;
98	  const pz = yMm / 1000;
99	  let best:
100	    | { wall: Extract<Element, { kind: 'wall' }>; alongT: number; distMm: number }
101	    | undefined;
102	  for (const el of Object.values(elementsById)) {
103	    if (el.kind !== 'wall') continue;
104	    if (activeLevelId && el.levelId !== activeLevelId) continue;
105	    const ax = el.start.xMm / 1000;
106	    const az = el.start.yMm / 1000;
107	    const bx = el.end.xMm / 1000;
108	    const bz = el.end.yMm / 1000;
109	    const abx = bx - ax;
110	    const abz = bz - az;
111	    const len2 = abx * abx + abz * abz;
112	    const rawT = Math.max(
113	      0,
114	      Math.min(1, ((px - ax) * abx + (pz - az) * abz) / Math.max(len2, 1e-9)),
115	    );
116	    const fx = ax + abx * rawT;
117	    const fz = az + abz * rawT;
118	    const distMm = Math.hypot((px - fx) * 1000, (pz - fz) * 1000);
119	    if (!best || distMm < best.distMm) best = { wall: el, alongT: rawT, distMm };
120	  }
121	  return best;
122	}
