124	function guessGridLabel(sxMm: number, syMm: number, exMm: number, eyMm: number) {
125	  const horizontal = Math.abs(eyMm - syMm) < Math.abs(exMm - sxMm);
126	  return horizontal
127	    ? `Axis ${Math.floor(Math.abs((syMm + 5000) / 3800)) + 1}`
128	    : String.fromCharCode(66 + Math.min(10, Math.floor(Math.abs(exMm - sxMm + 8200) / 4200)));
129	}
