186	  const lastPlotScaleRef = useRef<number>(0);
187	  const snapEngineRef = useRef(new SnapEngine());
188	  const snapIndicatorRef = useRef<THREE.Mesh | null>(null);
189	  const [snapLabel, setSnapLabel] = useState<string | null>(null);
190	  const [hudMm, setHudMm] = useState<{ xMm: number; yMm: number }>();
191	  const [halfUi, setHalfUi] = useState(22);
192	  const [showZoomMenu, setShowZoomMenu] = useState(false);
193	  const [geomEpoch, bumpGeom] = useState(0);
194	  const [roomColorLegend, setRoomColorLegend] = useState<
195	    Array<{
196	      label: string;
197	      schemeColorHex: string;
198	      programmeCode?: string;
199	      department?: string;
