209	  const [wireTagStyleHints, setWireTagStyleHints] = useState<ReturnType<
210	    typeof extractPlanTagStyleHints
211	  > | null>(null);
212	
213	  const elementsById = useBimStore((s) => s.elementsById);
214	  const selectedId = useBimStore((s) => s.selectedId);
