216	  const revision = useBimStore((s) => s.revision);
217	  const planProjectionPrimitives = useBimStore((s) => s.planProjectionPrimitives);
218	  const setPlanProjectionPrimitives = useBimStore((s) => s.setPlanProjectionPrimitives);
219	  const setPlanRoomSchemeWireReadout = useBimStore((s) => s.setPlanRoomSchemeWireReadout);
220	  const activePlanViewId = useBimStore((s) => s.activePlanViewId);
