224	  const selectEl = useBimStore((s) => s.select);
225	
226	  const display = useMemo(
227	    () =>
228	      resolvePlanViewDisplay(
229	        elementsById,
230	        activePlanViewId,
231	        activeLevelResolvedId || undefined,
