233	      ),
234	    [elementsById, activePlanViewId, activeLevelResolvedId, planPresentation],
235	  );
236	
237	  const mergedGraphicHints = useMemo(() => {
238	    if (wireGraphicHints) return wireGraphicHints;
239	    return resolvePlanGraphicHints(elementsById, activePlanViewId);
240	  }, [wireGraphicHints, elementsById, activePlanViewId]);
241	
242	  const mergedAnnotationHints = useMemo(() => {
243	    if (wireAnnotationHints !== null) return wireAnnotationHints;
244	    return resolvePlanAnnotationHints(elementsById, activePlanViewId);
245	  }, [wireAnnotationHints, elementsById, activePlanViewId]);
246	
247	  const planTagFontScales = useMemo(() => {
248	    const pvId = display.planViewElementId;
249	    const ro = resolvePlanTagStyleLane(elementsById, pvId, 'opening');
250	    const rr = resolvePlanTagStyleLane(elementsById, pvId, 'room');
251	    const bo = wireTagStyleHints?.opening?.textSizePt;
252	    const br = wireTagStyleHints?.room?.textSizePt;
253	    const openingPt = typeof bo === 'number' && Number.isFinite(bo) ? bo : ro.textSizePt;
254	    const roomPt = typeof br === 'number' && Number.isFinite(br) ? br : rr.textSizePt;
255	    return { opening: openingPt / 10, room: roomPt / 10 };
256	  }, [wireTagStyleHints, elementsById, display.planViewElementId]);
257	
258	  const hiddenKey = useMemo(
259	    () => [...display.hiddenSemanticKinds].sort().join('|'),
260	    [display.hiddenSemanticKinds],
261	  );
262	
263	  const displayLevelId = display.activeLevelId;
264	  const anchors = useMemo(
265	    () => collectWallAnchors(elementsById, displayLevelId || undefined),
