268	  const lvlId = displayLevelId || activeLevelResolvedId;
269	
270	  useEffect(() => {
271	    let cancel = false;
272	    if (!modelId) {
273	      queueMicrotask(() => {
274	        if (cancel) return;
275	        setPlanProjectionPrimitives(null);
276	        setPlanRoomSchemeWireReadout(null);
277	        setRoomColorLegend([]);
278	        setWireGraphicHints(null);
279	        setWireAnnotationHints(null);
280	        setWireTagStyleHints(null);
281	      });
282	      return () => {
283	        cancel = true;
284	      };
285	    }
286	    void (async () => {
287	      try {
288	        const qs = buildPlanProjectionQuery({
289	          planViewId: display.planViewElementId,
290	          fallbackLevelId: display.planViewElementId ? undefined : lvlId || undefined,
291	          globalPresentation: planPresentation,
292	        });
293	        const payload = await fetchPlanProjectionWire(modelId, qs);
294	        if (cancel) return;
295	        const legendRows = extractRoomColorLegend(payload);
296	        setPlanProjectionPrimitives(extractPlanPrimitives(payload));
297	        setPlanRoomSchemeWireReadout({
298	          roomColorLegendRows: legendRows,
299	          programmeLegendEvidence: extractRoomProgrammeLegendEvidenceV0(payload),
300	          planCategoryGraphicHintsV0: extractPlanCategoryGraphicHintsV0(payload),
301	        });
302	        setRoomColorLegend(legendRows);
303	        setWireGraphicHints(extractPlanGraphicHints(payload));
304	        setWireAnnotationHints(extractPlanAnnotationHints(payload));
305	        setWireTagStyleHints(extractPlanTagStyleHints(payload));
306	      } catch {
307	        if (!cancel) setPlanProjectionPrimitives(null);
308	        if (!cancel) setPlanRoomSchemeWireReadout(null);
309	        if (!cancel) setRoomColorLegend([]);
310	        if (!cancel) setWireGraphicHints(null);
311	        if (!cancel) setWireAnnotationHints(null);
312	        if (!cancel) setWireTagStyleHints(null);
313	      }
314	    })();
315	    return () => {
316	      cancel = true;
317	    };
318	  }, [
319	    modelId,
320	    revision,
321	    display.planViewElementId,
322	    lvlId,
323	    planPresentation,
324	    setPlanProjectionPrimitives,
325	    setPlanRoomSchemeWireReadout,
326	  ]);
327	
328	  const resizeCam = useCallback(() => {
329	    const host = mountRef.current;
330	    const renderer = rendererRef.current;
331	    const camera = cameraRef.current;
332	    if (!host || !renderer || !camera) return;
333	    const w = Math.max(1, host.clientWidth);
334	    const h = Math.max(1, host.clientHeight);
335	    renderer.setSize(w, h);
336	    const asp = w / h;
